import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input with sanitization
        PrintWriter out = new PrintWriter("output.html");
        out.println("<html>");
        out.println("<body>");
        out.println("<p>User Input: " + StringEscapeUtils.escapeHtml4(userInput) + "</p>"); // Escaping user input
        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
